import re

# Load UC patent numbers
uc_var = locals()['var_function-call-4662591423543922160']
if isinstance(uc_var, str):
    uc_patents_list = json.loads(uc_var)
else:
    uc_patents_list = uc_var

uc_pub_nums = set(uc_patents_list)

# Load the big file with other patents
file_path = locals()['var_function-call-2391854350082773367']
with open(file_path, 'r') as f:
    other_patents = json.load(f)

def get_assignee(text):
    m = re.match(r"^(.*?) holds the ", text)
    if m: return m.group(1)
    m = re.search(r"(?:owned|held|assigned|belonging) (?:by|to) (.*?) (?:and|, with)", text)
    if m: return m.group(1)
    return None

results = set()

for row in other_patents:
    citations = row.get('citation')
    if not citations: continue

    # citation is a JSON string
    try:
        cit_list = json.loads(citations)
    except:
        continue

    cited_uc = False
    for c in cit_list:
        if c.get('publication_number') in uc_pub_nums:
            cited_uc = True
            break

    if cited_uc:
        assignee = get_assignee(row['Patents_info'])
        if not assignee:
            # Try to grab the first few words if patterns fail? No, safer to skip or refine.
            # Example: "Patent filing ... from ..., held by XYZ, with ..." handled by pattern 2?
            # Pattern 2: (?:owned|held...) (?:by|to) (.*?) (?:and|, with)
            # If "with" is not present, it might fail.
            # Let's add a fallback: if " assigned to " exists.
            m = re.search(r" assigned to (.*?) and", row['Patents_info'])
            if m: assignee = m.group(1)

        # Clean assignee name (remove "The ", etc if captured)
        if assignee:
            assignee = assignee.strip()

        # Extract Primary CPC Subclass
        cpc_json = row.get('cpc')
        subclass = None
        if cpc_json:
            try:
                cpc_list = json.loads(cpc_json)
                if cpc_list and len(cpc_list) > 0:
                    primary = cpc_list[0]
                    for item in cpc_list:
                        if item.get('first') is True:
                            primary = item
                            break
                    code = primary.get('code', '')
                    if len(code) >= 4:
                        subclass = code[:4]
            except:
                pass

        if assignee and subclass:
            # Exclude UNIV CALIFORNIA if regex captured it (though we filtered in SQL, regex might capture variations)
            if "UNIV CALIFORNIA" not in assignee and "UNIVERSITY OF CALIFORNIA" not in assignee:
                results.add((assignee, subclass))

print("__RESULT__:")
print(json.dumps(list(results)))
